import React, { useEffect, useState } from 'react';
import axios from 'axios';

function App() {
  const [sanPhams, setSanPhams] = useState([]);

  useEffect(() => {
    axios.get('http://localhost:3000/api/san-pham')
      .then(res => setSanPhams(res.data))
      .catch(err => console.error("Lỗi gọi API:", err));
  }, []);

  return (
    <div style={{ padding: '20px', fontFamily: 'Arial' }}>
      <h1>🖥️ Danh Sách Linh Kiện Build PC</h1>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '20px' }}>
        {sanPhams.map(item => (
          <div key={item._id} style={{ border: '1px solid #ddd', padding: '15px', borderRadius: '8px' }}>
            <h3>{item.ten}</h3>
            <p>Loại: <b>{item.loai}</b></p>
            <p style={{ color: 'red', fontWeight: 'bold' }}>Giá: {item.gia.toLocaleString()} VNĐ</p>
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;
